import { useState, useEffect, useRef } from "react";
import { useSearchParams } from "react-router-dom";
import API from "../services/api";
import { supabase } from "../services/supabaseClient";

export default function Upload({ user, setUser }) {
  const [searchParams] = useSearchParams();
  const featureParam = searchParams.get("feature");

  const [file, setFile] = useState(null);
  const [text, setText] = useState("");
  const [summary, setSummary] = useState("");
  const [showSummary, setShowSummary] = useState(false);
  const [loading, setLoading] = useState(false);

  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [asking, setAsking] = useState(false);

  const [docId, setDocId] = useState(null);
  const [userId, setUserId] = useState(null);

  const [papers, setPapers] = useState([]);

  // IDEAS STATE
  const [ideas, setIdeas] = useState([]);
  const [keywords, setKeywords] = useState([]);
  const [domain, setDomain] = useState("");
  const [subdomain, setSubdomain] = useState("");

  // AUTO TRIGGER
  const [autoRunIdeas, setAutoRunIdeas] = useState(false);
  const [mode, setMode] = useState(null); // 'ask', 'summary', 'recommend', 'ideas'

  const askRef = useRef(null);
  const summaryRef = useRef(null);
  const recommendRef = useRef(null);
  const ideasRef = useRef(null);

  // Auth Header
  const getAuthHeader = async () => {
    const { data: { session } } = await supabase.auth.getSession();
    return session ? { Authorization: `Bearer ${session.access_token}` } : {};
  };

  // Handle feature param from URL
  useEffect(() => {
    if (featureParam) {
      setMode(featureParam);
    }
  }, [featureParam]);

  // Scroll to section when mode changes and text is available
  useEffect(() => {
    if (mode && text) {
      setTimeout(() => {
        if (mode === 'ask' && askRef.current) {
          askRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
        } else if (mode === 'summary' && summaryRef.current) {
          summaryRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
        } else if (mode === 'recommend' && recommendRef.current) {
          recommendRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
        } else if (mode === 'ideas' && ideasRef.current) {
          ideasRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }, 300);
    }
  }, [mode, text]);

  // Upload
  const handleUpload = async () => {
    if (!file) return alert("Select a file");

    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const formData = new FormData();
      formData.append("file", file);

      const res = await API.post("/upload", formData, {
        headers: {
          ...authHeader,
          "Content-Type": "multipart/form-data"
        }
      });

      setText(res.data.preview);
      setDocId(res.data.doc_id);
      setUserId(res.data.user_id);

      // reset states
      setAnswer("");
      setQuestion("");
      setSummary("");
      setShowSummary(false);
      setPapers([]);
      setIdeas([]);
      setKeywords([]);
      setDomain("");
      setSubdomain("");

    } catch (err) {
      console.error(err);
      alert("Upload failed ❌");
    } finally {
      setLoading(false);
    }
  };

  // Q&A
  const askQuestion = async () => {
    if (!question || !docId) return alert("Upload + enter question");

    try {
      setAsking(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/ask", {
        question,
        doc_id: docId,
        user_id: userId
      }, { headers: authHeader });

      setAnswer(res.data.answer);

    } catch (err) {
      console.error(err);
    } finally {
      setAsking(false);
    }
  };

  // Summary
  const handleGenerateSummary = async () => {
    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/summarize", { text }, { headers: authHeader });

      setSummary(res.data.summary);
      setShowSummary(true);

    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // Recommendations
  const handleRecommend = async () => {
    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/recommend", {
        query: text
      }, { headers: authHeader });

      setPapers(res.data.recommendations || []);

    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // Ideas
  const handleIdeas = async () => {
    try {
      const authHeader = await getAuthHeader();

      const res = await API.post("/ideas", { text }, { headers: authHeader });

      setIdeas(res.data.ideas);
      setKeywords(res.data.keywords);
      setDomain(res.data.domain);
      setSubdomain(res.data.subdomain || "");

    } catch (err) {
      console.error(err);
      alert("Failed to generate ideas ❌");
    }
  };

  // CHECK LOCALSTORAGE TRIGGER
  useEffect(() => {
    if (localStorage.getItem("runIdeas") === "true") {
      setAutoRunIdeas(true);
      localStorage.removeItem("runIdeas");
    }
  }, []);

  // AUTO RUN AFTER UPLOAD
  useEffect(() => {
    if (autoRunIdeas && text) {
      handleIdeas();
      setAutoRunIdeas(false);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [autoRunIdeas, text]);

  // Show all buttons when no specific mode is selected
  const showAll = !mode;
  const showAsk = showAll || mode === 'ask';
  const showSummaryBtn = showAll || mode === 'summary';
  const showRecommendBtn = showAll || mode === 'recommend';
  const showIdeasBtn = showAll || mode === 'ideas';

  return (
    <div id="upload-section" className="space-y-6">

      {/* Upload Card */}
      <div className="bg-deepnavy-light border border-babyblue/10 p-6 rounded-2xl shadow-sm">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-sapphire to-cornflower flex items-center justify-center text-lg shadow-md shadow-sapphire/20">📄</div>
          <div>
            <h2 className="text-lg font-bold text-babyblue">Upload Research Paper</h2>
            <p className="text-sm text-periwinkle/50">Supported format: PDF</p>
          </div>
        </div>

        <div className="flex gap-3 items-center">
          <label className="flex-1 flex items-center gap-3 px-4 py-3 rounded-xl bg-deepnavy border-2 border-dashed border-babyblue/20 cursor-pointer hover:border-sapphire/50 transition-all group">
            <span className="text-xl group-hover:scale-110 transition-transform">📎</span>
            <span className="text-sm text-periwinkle/60 truncate">
              {file ? file.name : "Click to select a PDF file"}
            </span>
            <input
              type="file"
              accept=".pdf"
              onChange={(e) => setFile(e.target.files[0])}
              className="hidden"
            />
          </label>

          <button onClick={handleUpload} className="btn shadow-lg shadow-sapphire/20">
            {loading ? "Processing..." : "Upload"}
          </button>
        </div>
      </div>

      {/* Preview */}
      {text && (
        <div className="bg-deepnavy-light border border-babyblue/10 p-5 rounded-2xl">
          <div className="flex items-center gap-2 mb-2">
            <span className="w-2 h-2 rounded-full bg-cornflower"></span>
            <h3 className="font-bold text-babyblue text-sm uppercase tracking-wider">Preview</h3>
          </div>
          <p className="text-periwinkle/70 leading-relaxed text-sm">{text.slice(0, 500)}...</p>
        </div>
      )}

      {/* Feature-specific buttons */}
      {text && showSummary && (
        <div ref={summaryRef}>
          <button onClick={handleGenerateSummary} className="btn shadow-lg shadow-sapphire/20 text-sm ring-2 ring-babyblue ring-offset-2 ring-offset-deepnavy">
            🧠 Generate Summary
          </button>
        </div>
      )}

      {text && showRecommend && (
        <div ref={recommendRef}>
          <button onClick={handleRecommend} className="btn shadow-lg shadow-sapphire/20 text-sm ring-2 ring-babyblue ring-offset-2 ring-offset-deepnavy">
            🔍 Find Recommendations
          </button>
        </div>
      )}

      {text && showIdeas && (
        <div ref={ideasRef}>
          <button onClick={handleIdeas} className="btn shadow-lg shadow-sapphire/20 text-sm ring-2 ring-babyblue ring-offset-2 ring-offset-deepnavy">
            💡 Generate Ideas
          </button>
        </div>
      )}

      {/* Summary Result */}
      {showSummary && (
        <div className="bg-deepnavy/60 border border-babyblue/20 p-5 rounded-2xl">
          <div className="flex items-center gap-2 mb-2">
            <span className="w-2 h-2 rounded-full bg-sapphire"></span>
            <h3 className="font-bold text-babyblue text-sm uppercase tracking-wider">Summary</h3>
          </div>
          <p className="text-periwinkle/80 leading-relaxed text-sm">{summary}</p>
        </div>
      )}

      {/* Q&A */}
      {text && showAsk && (
        <div ref={askRef} className="bg-deepnavy-light border border-babyblue/10 p-5 rounded-2xl">
          <div className="flex items-center gap-2 mb-3">
            <span className="w-2 h-2 rounded-full bg-cornflower"></span>
            <h3 className="font-bold text-babyblue text-sm uppercase tracking-wider">Ask a Question</h3>
          </div>

          <div className="flex gap-2">
            <input
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              className="flex-1 border p-3 rounded-xl bg-deepnavy/40 text-babyblue border-babyblue/20 placeholder-babyblue/40 focus:outline-none focus:ring-2 focus:ring-sapphire/30 transition-all text-sm"
              placeholder="What is the main contribution of this paper?"
              onKeyDown={(e) => e.key === 'Enter' && askQuestion()}
            />
            <button onClick={askQuestion} className="btn shadow-lg shadow-sapphire/20 text-sm">
              {asking ? "Thinking..." : "Ask"}
            </button>
          </div>

          {answer && (
            <div className="mt-3 p-4 rounded-xl bg-deepnavy/40 border border-babyblue/10">
              <p className="text-periwinkle/80 leading-relaxed text-sm">{answer}</p>
            </div>
          )}
        </div>
      )}

      {/* Recommendations Result */}
      {papers.length > 0 && (
        <div className="bg-deepnavy-light border border-babyblue/10 p-5 rounded-2xl">
          <div className="flex items-center gap-2 mb-3">
            <span className="w-2 h-2 rounded-full bg-cornflower"></span>
            <h3 className="font-bold text-babyblue text-sm uppercase tracking-wider">Related Papers</h3>
          </div>
          <div className="space-y-2">
            {papers.map((p, i) => (
              <div key={i} className="p-3 rounded-lg bg-deepnavy/40 border border-babyblue/10 text-periwinkle/70 text-sm">
                {p}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Domain + Keywords */}
      {domain && (
        <div className="bg-deepnavy/60 border border-babyblue/20 p-5 rounded-2xl">
          <div className="flex items-center gap-2 mb-2">
            <span className="w-2 h-2 rounded-full bg-sapphire"></span>
            <h3 className="text-sm font-semibold text-babyblue">
              🧠 Domain: {domain}
            </h3>
          </div>

          {subdomain && (
            <p className="text-sm text-periwinkle/60 mb-3">
              Subdomain: {subdomain}
            </p>
          )}

          <div className="flex gap-2 flex-wrap">
            {keywords.map((k, i) => (
              <span
                key={i}
                className="bg-sapphire/20 text-babyblue px-3 py-1 rounded-full text-xs font-semibold border border-babyblue/20"
              >
                {k}
              </span>
            ))}
          </div>
        </div>
      )}

      {/* Ideas Result */}
      {ideas.length > 0 && (
        <div>
          <div className="flex items-center gap-2 mb-3">
            <span className="w-2 h-2 rounded-full bg-cornflower"></span>
            <h3 className="font-bold text-babyblue text-sm uppercase tracking-wider">Generated Ideas</h3>
          </div>
          <div className="grid md:grid-cols-2 gap-3">
            {ideas.map((idea, i) => (
              <div key={i} className="bg-deepnavy-light p-4 rounded-2xl shadow-sm border border-babyblue/10 hover:shadow-md hover:shadow-sapphire/5 transition-all duration-300 hover:-translate-y-1">
                <h3 className="font-bold text-babyblue mb-1 text-sm">{idea.title}</h3>
                <p className="text-sm text-periwinkle/70 mb-2">{idea.description}</p>
                <p className="text-xs text-periwinkle/50 mb-2">💡 {idea.use_case}</p>

                <ul className="text-xs text-periwinkle/60 list-disc ml-4 mb-2 space-y-0.5">
                  {idea.reasons?.map((r, idx) => (
                    <li key={idx}>{r}</li>
                  ))}
                </ul>

                <div className="flex justify-between items-center pt-2 border-t border-babyblue/10">
                  <span className="text-xs font-medium text-cornflower bg-cornflower/10 px-2 py-0.5 rounded-md">{idea.category}</span>
                  <span className="text-xs font-bold text-babyblue">Score: {idea.score}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

    </div>
  );
}
